TriggerOraclev10g.body:
DECLARE
    vro_tkr_hv_usuarios  tkr_hv_usuarios%ROWTYPE;
    CURSOR cur_hoja_vida IS
    SELECT * FROM TKR_HV_USUARIOS
     WHERE id_usuario = :new.id_usuario;
BEGIN
    IF :new.id_rol = 4 THEN
        OPEN cur_hoja_vida;
        FETCH cur_hoja_vida INTO vro_tkr_hv_usuarios;
        IF cur_hoja_vida%NOTFOUND THEN
            INSERT INTO TKR_HV_USUARIOS (id, id_usuario)
              VALUES (tkr_hv_usuarios_seq.nextval, :new.id_usuario);
        END IF;
        CLOSE cur_hoja_vida;
    END IF;
END;
